// ─── TypeNode JSON converter ───────────────────────────────────────────────────

public sealed class TypeNodeConverter : JsonConverter<TypeNode>
{
    public override TypeNode? Read(ref Utf8JsonReader reader, Type typeToConvert, JsonSerializerOptions options)
    {
        if (reader.TokenType == JsonTokenType.Null) return null;

        using var doc = JsonDocument.ParseValue(ref reader);
        var root = doc.RootElement;
        var kind = root.GetProperty("kind").GetString() ?? "unknown";
        var syntaxKind = root.TryGetProperty("syntaxKind", out var sk) ? sk.GetString() : null;
        var checkerType = root.TryGetProperty("checkerType", out var ct) ? ct.GetString() : null;
        var transport = root.TryGetProperty("transport", out var tm)
            ? tm.Deserialize<TransportModel>(options)
            : null;

        TypeNode node = kind switch
        {
            "keyword" => new KeywordTypeNode(
                root.TryGetProperty("name", out var kn) ? kn.GetString() ?? kind : kind),
            "reference" => new ReferenceTypeNode(
                root.TryGetProperty("name", out var rn) ? rn.GetString() ?? "" : "",
                root.TryGetProperty("resolvedSymbol", out var rs) ? rs.GetString() : null,
                root.TryGetProperty("typeArguments", out var rta)
                    ? rta.Deserialize<IReadOnlyList<TypeNode>>(options) ?? []
                    : []),
            "union" => new UnionTypeNode(
                root.TryGetProperty("types", out var ut)
                    ? ut.Deserialize<IReadOnlyList<TypeNode>>(options) ?? []
                    : []),
            "intersection" => new IntersectionTypeNode(
                root.TryGetProperty("types", out var it)
                    ? it.Deserialize<IReadOnlyList<TypeNode>>(options) ?? []
                    : []),
            "literal" => new LiteralTypeNode(
                root.TryGetProperty("literalKind", out var lk) ? lk.GetString() ?? "" : "",
                root.TryGetProperty("text", out var lt) ? lt.GetString() ?? "" : ""),
            "array" => new ArrayTypeNode(
                root.TryGetProperty("elementType", out var at)
                    ? at.Deserialize<TypeNode>(options) ?? new UnknownTypeNode("array/unknown")
                    : new UnknownTypeNode("array/missing")),
            "tuple" => new TupleTypeNode(
                root.TryGetProperty("elements", out var tte)
                    ? tte.Deserialize<IReadOnlyList<TypeNode>>(options) ?? []
                    : []),
            "namedTupleMember" => new NamedTupleMemberTypeNode(
                root.TryGetProperty("name", out var ntmn)
                    ? ntmn.GetString() ?? ""
                    : "",
                root.TryGetProperty("optional", out var ntmo)
                    && ntmo.GetBoolean(),
                root.TryGetProperty("rest", out var ntmr)
                    && ntmr.GetBoolean(),
                root.TryGetProperty("type", out var ntmt)
                    ? ntmt.Deserialize<TypeNode>(options)
                        ?? new UnknownTypeNode("namedTupleMember/unknown")
                    : new UnknownTypeNode("namedTupleMember/missing")),
            "optional" => new OptionalTypeNode(
                root.TryGetProperty("type", out var opt)
                    ? opt.Deserialize<TypeNode>(options)
                        ?? new UnknownTypeNode("optional/unknown")
                    : new UnknownTypeNode("optional/missing")),
            "rest" => new RestTypeNode(
                root.TryGetProperty("type", out var rest)
                    ? rest.Deserialize<TypeNode>(options)
                        ?? new UnknownTypeNode("rest/unknown")
                    : new UnknownTypeNode("rest/missing")),
            "function" => new FunctionTypeNode(
                root.TryGetProperty("typeParameters", out var ftp)
                    ? ftp.Deserialize<IReadOnlyList<TypeParameterModel>>(options) ?? []
                    : [],
                root.TryGetProperty("parameters", out var fp)
                    ? fp.Deserialize<IReadOnlyList<ParameterModel>>(options) ?? []
                    : [],
                root.TryGetProperty("returnType", out var frt)
                    ? frt.Deserialize<TypeNode>(options) ?? new KeywordTypeNode("VoidKeyword")
                    : new KeywordTypeNode("VoidKeyword")),
            "typeLiteral" => new TypeLiteralTypeNode(
                root.TryGetProperty("members", out var tlm)
                    ? tlm.Deserialize<IReadOnlyList<MemberModel>>(options) ?? []
                    : []),
            "templateLiteral" => new TemplateLiteralTypeNode(
                root.TryGetProperty("head", out var tlh)
                    ? tlh.GetString() ?? ""
                    : "",
                root.TryGetProperty("spans", out var tls)
                    ? tls.Deserialize<IReadOnlyList<TemplateLiteralSpanModel>>(options)
                        ?? []
                    : root.TryGetProperty("parts", out var tlp)
                        ? (tlp.Deserialize<IReadOnlyList<TypeNode>>(options) ?? [])
                            .Select(part => new TemplateLiteralSpanModel(part, ""))
                            .ToList()
                        : []),
            "query" => new QueryTypeNode(
                root.TryGetProperty("exprType", out var qt)
                    ? qt.Deserialize<TypeNode>(options)
                    : null,
                root.TryGetProperty("expressionName", out var qen)
                    ? qen.GetString()
                    : null,
                root.TryGetProperty("resolvedSymbol", out var qrs)
                    ? qrs.GetString()
                    : null,
                root.TryGetProperty("typeArguments", out var qta)
                    ? qta.Deserialize<IReadOnlyList<TypeNode>>(options) ?? []
                    : []),
            "indexedAccess" => new IndexedAccessTypeNode(
                root.TryGetProperty("objectType", out var iao)
                    ? iao.Deserialize<TypeNode>(options) ?? new UnknownTypeNode("indexed/obj")
                    : new UnknownTypeNode("indexed/obj"),
                root.TryGetProperty("indexType", out var iai)
                    ? iai.Deserialize<TypeNode>(options) ?? new UnknownTypeNode("indexed/idx")
                    : new UnknownTypeNode("indexed/idx")),
            "operator" => new OperatorTypeNode(
                root.TryGetProperty("operator", out var op) ? op.GetString() ?? "" : "",
                // IR extractor may use "operandType" or "type" for the operand property
                (root.TryGetProperty("operandType", out var ot) || root.TryGetProperty("type", out ot))
                    ? ot.Deserialize<TypeNode>(options) ?? new UnknownTypeNode("operator/operand")
                    : new UnknownTypeNode("operator/operand")),
            "heritageReference" => new HeritageReferenceTypeNode(
                root.TryGetProperty("expression", out var hre) ? hre.GetString() ?? "" : "",
                root.TryGetProperty("resolvedSymbol", out var hrrs) ? hrrs.GetString() : null,
                root.TryGetProperty("typeArguments", out var hrta)
                    ? hrta.Deserialize<IReadOnlyList<TypeNode>>(options) ?? []
                    : []),
            "parenthesized" => new ParenthesizedTypeNode(
                root.TryGetProperty("type", out var pt)
                    ? pt.Deserialize<TypeNode>(options) ?? new UnknownTypeNode("parenthesized/unknown")
                    : new UnknownTypeNode("parenthesized/missing")),
            "import" => new ImportTypeNode(
                root.TryGetProperty("argument", out var ita)
                    ? ita.Deserialize<TypeNode>(options)
                        ?? new UnknownTypeNode("import/argument")
                    : new UnknownTypeNode("import/missingArgument"),
                root.TryGetProperty("qualifier", out var itq)
                    && itq.ValueKind != JsonValueKind.Null
                        ? itq.GetString()
                        : null,
                root.TryGetProperty("typeArguments", out var itta)
                    ? itta.Deserialize<IReadOnlyList<TypeNode>>(options) ?? []
                    : [],
                root.TryGetProperty("isTypeOf", out var itto)
                    && itto.GetBoolean(),
                root.TryGetProperty("attributes", out var itat)
                    && itat.ValueKind != JsonValueKind.Null
                        ? itat.GetString()
                        : null),
            _ => new UnknownTypeNode(kind),
        };

        return node with
        {
            SyntaxKind = syntaxKind,
            CheckerType = checkerType,
            Transport = transport,
        };
    }

    public override void Write(Utf8JsonWriter writer, TypeNode value, JsonSerializerOptions options)
        => throw new NotSupportedException("TypeNode serialization is not needed.");
}

