/// <summary>
/// Converts a declaration-level extendedAttributes value that may be a single object
/// or an array of objects into a list.
/// </summary>
public sealed class WebIdlExtAttrListConverter : JsonConverter<IReadOnlyList<WebIdlExtAttrDetail>>
{
    public override IReadOnlyList<WebIdlExtAttrDetail>? Read(
        ref Utf8JsonReader reader, Type typeToConvert, JsonSerializerOptions options)
    {
        if (reader.TokenType == JsonTokenType.Null)
            return [];
        if (reader.TokenType == JsonTokenType.StartArray)
            return JsonSerializer.Deserialize<List<WebIdlExtAttrDetail>>(ref reader, options) ?? [];
        if (reader.TokenType == JsonTokenType.StartObject)
        {
            var single = JsonSerializer.Deserialize<WebIdlExtAttrDetail>(ref reader, options);
            return single is null ? [] : [single];
        }
        throw new JsonException(
            $"Unexpected token {reader.TokenType} for WebIdlExtAttrDetail list.");
    }
    public override void Write(Utf8JsonWriter writer,
        IReadOnlyList<WebIdlExtAttrDetail> value, JsonSerializerOptions options)
        => throw new NotSupportedException();
}

